import { defineConfig, devices } from "@playwright/test";

/**
 * See https://playwright.dev/docs/test-configuration.
 */
export default defineConfig({
  testDir: "./src/e2e",
  fullyParallel: true,
  forbidOnly: !!process.env.CI,
  retries: process.env.CI ? 2 : 0,
  workers: process.env.CI ? 1 : undefined,
  reporter: "html",
  // Fidelity screenshot baselines are per-run artefacts generated by
  // bin/fidelity.mjs against a chosen git ref — never committed.
  snapshotPathTemplate: ".fidelity/snapshots/{arg}{ext}",
  expect: {
    toHaveScreenshot: {
      animations: "disabled",
    },
  },
  use: {
    trace: "on-first-retry",
    screenshot: "only-on-failure",
    ignoreHTTPSErrors: true,
  },
  projects: [
    {
      name: "chromium",
      use: { ...devices["Desktop Chrome"] },
      testIgnore: "**/fidelity.spec.ts",
    },
    // Screenshot catalogue for bin/fidelity.mjs (which sets FIDELITY=1).
    // Only defined when opted into so a plain `playwright test` doesn't
    // compare against stale baselines from a previous harness run.
    ...(process.env.FIDELITY
      ? [
          {
            name: "fidelity",
            testMatch: "**/fidelity.spec.ts",
            // The harness runs against freshly started dev servers; first
            // visits pay vite's on-demand compile, so allow a warm-server
            // retry.
            timeout: 60_000,
            retries: 1,
            use: {
              ...devices["Desktop Chrome"],
              contextOptions: { reducedMotion: "reduce" as const },
            },
          },
        ]
      : []),
  ],
  /* Run local dev server before starting the tests, unless an external
     harness (bin/fidelity.mjs) manages its own servers. */
  webServer: process.env.FIDELITY_NO_WEBSERVER
    ? undefined
    : {
        ...(process.env.CI
          ? {
              command: `npx vite preview --port 5173 --base ${process.env.BASE_URL}`,
              url: `http://localhost:5173${process.env.BASE_URL}`,
            }
          : {
              command: "npx vite dev",
              url: "http://localhost:5173/",
            }),
        reuseExistingServer: !process.env.CI,
        stdout: "pipe",
        ignoreHTTPSErrors: true,
      },
});
